function maxProfitAssignment(difficulty, profit, worker) {
    const n = difficulty.length;
    const jobs = difficulty.map((d, i) => [d, profit[i]]).sort((a, b) => a[0] - b[0]);

    worker.sort((a, b) => a - b);

    let max_profit = 0;
    let total_profit = 0;
    let job_idx = 0;

    for (const w of worker) {
        while (job_idx < n && w >= jobs[job_idx][0]) {
            max_profit = Math.max(max_profit, jobs[job_idx][1]);
            job_idx++;
        }
        total_profit += max_profit;
    }

    return total_profit;
}
```


    1. Combine the difficulty and profit arrays into one array, called jobs, containing pairs of the values (in JavaScript, arrays of arrays), and sort it based on the difficulty values.
2. Sort the worker array in ascending order.
3. Initially, set the max_profit and total_profit to 0, and job_idx to 0.
4. Iterate over the worker array.
   a. Inside the loop, while job_idx is less than n (number of jobs) and the current worker's ability is greater than or equal to the current job's difficulty, update the max_profit to be the maximum of the current max_profit and the current job's profit, and increment job_idx.
   b. After the inner loop, add max_profit to the total_profit.
5. Return the total_profit.

